class Banner extends BaseBanner
{
    public function save(Doctrine_Connection $conn = null)
    {
        parent::save($conn);

        $translation = new Translation();
        $translation->setTranslation('banner','title',parent::_get("id"), parent::_get("title"));

        $translation = new Translation();
        $translation->setTranslation('banner','description',parent::_get("id"), parent::_get("description"));
    }

    public function getTitle()
	{
		$translation = new Translation();
		if($translation->getTranslation('banner','title',$this->getId()))
        {
          	return $translation->getTranslation('banner','title',$this->getId());
        }
        else
        {
        	return parent::_get("title");
        }
	}

	public function getDescription()
	{
		$translation = new Translation();
		if($translation->getTranslation('banner','description',$this->getId()))
        {
          	return $translation->getTranslation('banner','description',$this->getId());
        }
        else
        {
        	return parent::_get("description");
        }
	}
}
